mapper.select:
SELECT mca.id, mca.student_id AS studentId, st.student_no AS studentNo, st.student_name AS studentName, mca.original_mentor_id AS originalMentorId, ot.teacher_no AS originalMentorNo, ot.teacher_name AS originalMentorName, mca.new_mentor_id AS newMentorId, nt.teacher_no AS newMentorNo, nt.teacher_name AS newMentorName, mca.change_reason AS changeReason, mca.original_mentor_status AS originalMentorStatus, mca.original_mentor_comment AS originalMentorComment, mca.original_mentor_time AS originalMentorTime, mca.new_mentor_status AS newMentorStatus, mca.new_mentor_comment AS newMentorComment, mca.new_mentor_time AS newMentorTime, mca.overall_status AS overallStatus, mca.apply_time AS applyTime, mca.create_time AS createTime, mca.update_time AS updateTime FROM mentor_change_application mca LEFT JOIN student st ON mca.student_id = st.id LEFT JOIN teacher ot ON mca.original_mentor_id = ot.id LEFT JOIN teacher nt ON mca.new_mentor_id = nt.id
AND mca.student_id = #{studentId}
AND mca.overall_status = #{overallStatus}
AND st.student_no LIKE CONCAT('%', #{studentNo}, '%')
AND st.student_name LIKE CONCAT('%', #{studentName}, '%')
ORDER BY mca.create_time DESC
